import React from 'react';
import './NavBar.css';

function NavBar({ active = 'record', onNavigate }) {
  const tabs = [
    { id: 'calendar', icon: '📅', label: 'Calendar' },
    { id: 'record', icon: '🎙', label: 'Record' },
    { id: 'community', icon: '👥', label: 'Community' },
    { id: 'profile', icon: '👤', label: 'Profile' },
  ];

  return (
    <nav className="navbar">
      {tabs.map((tab) => (
        <button
          key={tab.id}
          className={`navbar-tab ${active === tab.id ? 'active' : ''}`}
          onClick={() => onNavigate && onNavigate(tab.id)}
        >
          <span className="navbar-icon">{tab.icon}</span>
          <span className="navbar-label">{tab.label}</span>
        </button>
      ))}
    </nav>
  );
}

export default NavBar;
